import { ImageWrapper, InputLabel, ImageContent, ImageThumbnail, ImageInfo, ImageTitle, ImageDetail } from "./ImagePreview.styles"

export const ImagePreview = ({ id, label, src, name, extra }) => {
    return (
        <ImageWrapper>
            <InputLabel htmlFor={id}>
                {label}
            </InputLabel>
            <ImageContent>
                <ImageThumbnail>
                    {src ? (
                        <img alt={name} src={src} />
                    ) : (
                        <svg
                            xmlns="http://www.w3.org/2000/svg"
                            viewBox="0 0 24 24"
                            fill="currentColor"
                            className="size-6"
                        >
                            <path
                                fillRule="evenodd"
                                d="M1.5 6a2.25 2.25 0 0 1 2.25-2.25h16.5A2.25 2.25 0 0 1 22.5 6v12a2.25 2.25 0 0 1-2.25 2.25H3.75A2.25 2.25 0 0 1 1.5 18V6ZM3 16.06V18c0 .414.336.75.75.75h16.5A.75.75 0 0 0 21 18v-1.94l-2.69-2.689a1.5 1.5 0 0 0-2.12 0l-.88.879.97.97a.75.75 0 1 1-1.06 1.06l-5.16-5.159a1.5 1.5 0 0 0-2.12 0L3 16.061Zm10.125-7.81a1.125 1.125 0 1 1 2.25 0 1.125 1.125 0 0 1-2.25 0Z"
                                clipRule="evenodd"
                            />
                        </svg>
                    )}
                </ImageThumbnail>
                <ImageInfo>
                    <ImageTitle>Material Preview</ImageTitle>
                    <ImageDetail>
                        {src ? src.split("/").pop() : "No image"}
                    </ImageDetail>
                    {extra}
                </ImageInfo>
            </ImageContent>
        </ImageWrapper>
    )
}